public boolean canBalance(int[] nums) {
    int numsSum = 0;
    for (int i = 0; i < nums.length; i++) {
        numsSum += nums[i];
    }
    int leftSum = 0;
    for (int i = 0; i < nums.length; i++) {
        numsSum -= nums[i];
        if (leftSum == numsSum) {
            return true;
        }
        leftSum += nums[i];
    }
    return false;
}

