public String alarmClock(int day, boolean vacation) {
    String alarmTime;

    if (vacation) {
        if (day >= 0 && day <= 4) { // Monday - Friday
            alarmTime = "10:00";
        } else { // Saturday and Sunday
            alarmTime = "off";
        }
    } else {
        if (day >= 0 && day <= 4) { // Monday - Friday
            alarmTime = "7:00";
        } else { // Saturday and Sunday
            alarmTime = "10:00";
        }
    }
    return alarmTime;
}

